use std::collections::HashMap;
use std::sync::{Arc, Mutex};

type Cache = HashMap<String, String>;

struct Resolver {
    cache: Arc<Mutex<Cache>>,
}

impl Resolver {
    fn new() -> Self {
        Resolver { 
            cache: Arc::new(Mutex::new(HashMap::new()))
        }
    }

    fn get_address(&self, domain: &str) -> Option<String> {
        let cache_lock = self.cache.lock().unwrap();
        if let Some(addr) = cache_lock.get(domain) {
            return Some(addr.clone());
        }
        None
    }

    fn resolve(&self, domain: &str, handler: impl FnOnce(String) -> Result<String, String>) -> Result<String, String> {
        let mut cache_guard = self.cache.lock().unwrap();
        if let Some(cached_addr) = cache_guard.get(domain) {
            return Ok(cached_addr.clone());
        }

        let result = handler(domain.to_string());
        match result {
            Ok(addr) => {
                cache_guard.insert(domain.to_string(), addr.clone());
                Ok(addr)
            },
            Err(e) => {
                Err(format!("Failed to resolve {}: {}", domain, e))
            }
        }
    }
}

fn main() {
    let resolver = Resolver::new();

    let handle_a = |domain: String| -> Result<String, String> {
        println!("Performing network lookup for {}", domain);
        if domain.contains("fail") {
            Err(format!("DNS record not found for {}", domain))
        } else if domain == "example.com" {
            Ok("93.184.216.34".to_string())
        } else {
            Ok(domain + ":53")
        }
    };

    println!("--- First Lookup (example.com) ---");
    let result1 = resolver.resolve("example.com", handle_a);
