    let result4 = resolver.resolve("fail.com", handle_a);
    println!("Result 4: {:?}", result4); 
}

use std::collections::HashMap;
use std::fmt;

struct ConfigBlock {
    name: String,
    properties: HashMap<String, String>,
}

impl fmt::Display for ConfigBlock {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "[Block: {}] Properties: {:?}", self.name, self.properties)
    }
}

trait Validator<T> {
    fn validate(&self, item: &T) -> Result<(), String>;
}

struct SchemaValidator;

impl Validator<ConfigBlock> for SchemaValidator {
    fn validate(&self, block: &ConfigBlock) -> Result<(), String> {
        if block.properties.contains_key("resource_id") && block.properties["resource_id"].len() < 5 {
            return Err(format!("Resource ID {} is too short.", "resource_id"));
        }
        Ok(())
    }
}

fn main() {
    let mut blocks: Vec<Box<dyn Validator<ConfigBlock>>> = Vec::new();
    let block1 = ConfigBlock {
        name: String::from("network_interface"),
        properties: HashMap::from([("resource_id".to_string(), "abcde123".to_string())]),
    };
    let validator_impl = SchemaValidator;
    blocks.push(Box::new(validator_impl));

    println!("Validating block: {}", block1);

    for validator in blocks.iter() {
        match validator.validate(&block1) {
            Ok(()) => println!("Validation successful for all checks."),
            Err(e) => println!("Validation failed: {}", e),
        }
    }
}
